\begin{algorithm*}[H]
\caption{The pseudo-code for retrieval stage.}
\label{alg:retrieval-pseudo}
{\begin{algorithmic}[1]
\REQUIRE $q$, $\mathcal G$, $T$, $k$, $h$, $l$
\ENSURE Supplemental text $\mathcal C_s = \{c_1, c_2 \cdots c_n\}, n \leq k$
\STATE entities $\mathcal E_q = \mathtt{SpaCy}(q)$
\IF {Count($\mathcal E_q$) == 0}
\RETURN {$\bigstar$ {$\ \mathcal C_s = \mathtt{DenseRetrieval}(q, k)$}}
\ENDIF
\STATE selected pairs $\mathcal P_h =\mathtt{GraphFilter}(\mathcal E_q,h)$ \quad [Equation~\ref{eq0}]
\IF {Count ($\mathcal P_h$) == 0}
\STATE {$\bigstar\ $candidate supplementary chunks $\hat{\mathcal C} = \mathtt{DenseRetrieval}(q,2k)$}
\RETURN {$\bigstar\ $$\mathcal C_s = \mathtt{OccurrenceRank}(\hat{\mathcal C})$}
\ENDIF
\STATE candidate supplementary chunks $\hat{\mathcal C} = \mathtt{IndexMapping}(\mathcal P_h)$ \quad [Equation~\ref{eq1}]
\WHILE {Count($\hat{\mathcal C}$) $> 25$}
\STATE $h = h-1$ or $l = l + 1$
\STATE $\hat{\mathcal C}_\text{prev} = \hat{\mathcal C}$
\STATE $\mathcal P_h = \mathtt{GraphFilter}(\mathcal E_q, h)$\quad [Equation~\ref{eq0}]
\STATE $\hat{\mathcal C} = \mathtt{IndexMapping}(\mathcal P_h)$\quad [Equation~\ref{eq1}]
\ENDWHILE
\IF{Count($\hat{\mathcal C}$==0)}
\RETURN $\mathcal C_s = \mathtt{EntityAwareFilter}(\hat{\mathcal C}_\text{prev})$
\ELSE
\RETURN $\mathcal C_s = \hat{\mathcal C}$
\ENDIF
\end{algorithmic}}
\end{algorithm*}

